#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

/* Check if sensor data has timed out (more than 1000ms since last valid sample) */
static bool is_sensor_timeout(controller_t *controller, uint32_t now_ms, bool has_sensor)
{
    if (!has_sensor) {
        return true;
    }
    /* For temperature: check against last_temperature_ms */
    if (controller->last_temperature_ms > 0 &&
        (now_ms - controller->last_temperature_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return true;
    }
    /* For level: check against last_level_ms */
    if (controller->last_level_ms > 0 &&
        (now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
        return true;
    }
    return false;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Handle sensor timeout/malformed input - go to safe state */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller->has_valid_temperature = false;
        controller->has_valid_level = false;
        controller_set_safe_idle(controller);
        output.timed_out = true;
    } else if (input.kind == CONTROLLER_INPUT_NONE) {
        /* Check for timeout on stale sensor data */
        bool temp_timeout = is_sensor_timeout(controller, input.now_ms, controller->has_valid_temperature);
        bool level_timeout = is_sensor_timeout(controller, input.now_ms, controller->has_valid_level);

        if (temp_timeout || level_timeout) {
            controller->has_valid_temperature = false;
            controller->has_valid_level = false;
            controller_set_safe_idle(controller);
            output.timed_out = true;
        } else if (controller->has_valid_temperature && controller->has_valid_level) {
            /* Both sensors valid, apply control policy */
            int level = controller->last_level;
            int temp = controller->last_temperature_c;

            /* Policy: If LEVEL < 60, command INLET OPEN and HEATER OFF */
            if (level < 60) {
                controller->inlet_open = true;
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_FILLING;
            }
            /* Policy: If LEVEL > 75, command INLET CLOSED */
            else if (level > 75) {
                controller->inlet_open = false;
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HEATING;
            }
            /* Policy: If LEVEL < 55 at any time, keep HEATER OFF */
            else if (level < 55) {
                controller->inlet_open = false;
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_FILLING;
            }
            /* Policy: If 60 <= LEVEL <= 75 and TEMP < 45, command INLET CLOSED and HEATER ON */
            else if (level >= 60 && level <= 75 && temp < 45) {
                controller->inlet_open = false;
                controller->heater_on = true;
                controller->state = CONTROLLER_STATE_HEATING;
            }
            /* Policy: If 45 <= TEMP < 47, hold the previous safe heater state */
            else if (temp >= 45 && temp < 47) {
                controller->inlet_open = false;
                /* Hold previous heater state - don't change it */
                controller->state = CONTROLLER_STATE_HOLDING;
            }
            /* Policy: If 47 <= TEMP <= 48 and temperature is rising, command HEATER OFF early */
            else if (temp >= 47 && temp <= 48) {
                controller->inlet_open = false;
                /* Check if temperature is rising compared to previous sample */
                if (controller->previous_temperature_c > 0 && temp > controller->previous_temperature_c) {
                    controller->heater_on = false;
                    controller->state = CONTROLLER_STATE_HEATING;
                } else {
                    /* Not rising, hold the previous safe heater state */
                    controller->state = CONTROLLER_STATE_HOLDING;
                }
            }
            /* Policy: If TEMP > 48, command INLET CLOSED and HEATER OFF */
            else if (temp > 48) {
                controller->inlet_open = false;
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HEATING;
            }
            /* Default: stay in current safe state */
            else {
                controller->inlet_open = false;
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_SAFE_IDLE;
            }
        }
        /* If not both sensors valid, stay in safe idle */
    } else if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        /* Update temperature freshness only */
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;

        /* Only apply control if both sensors are valid */
        if (controller->has_valid_level) {
            int level = controller->last_level;
            int temp = input.temperature_c;

            /* Policy: If LEVEL < 60, command INLET OPEN and HEATER OFF */
            if (level < 60) {
                controller->inlet_open = true;
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_FILLING;
            }
            /* Policy: If LEVEL > 75, command INLET CLOSED */
            else if (level > 75) {
                controller->inlet_open = false;
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HEATING;
            }
            /* Policy: If LEVEL < 55 at any time, keep HEATER OFF */
            else if (level < 55) {
                controller->inlet_open = false;
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_FILLING;
            }
            /* Policy: If 60 <= LEVEL <= 75 and TEMP < 45, command INLET CLOSED and HEATER ON */
            else if (level >= 60 && level <= 75 && temp < 45) {
                controller->inlet_open = false;
                controller->heater_on = true;
                controller->state = CONTROLLER_STATE_HEATING;
            }
            /* Policy: If 45 <= TEMP < 47, hold the previous safe heater state */
            else if (temp >= 45 && temp < 47) {
                controller->inlet_open = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            }
            /* Policy: If 47 <= TEMP <= 48 and temperature is rising, command HEATER OFF early */
            else if (temp >= 47 && temp <= 48) {
                controller->inlet_open = false;
                if (controller->previous_temperature_c > 0 && temp > controller->previous_temperature_c) {
                    controller->heater_on = false;
                    controller->state = CONTROLLER_STATE_HEATING;
                } else {
                    controller->state = CONTROLLER_STATE_HOLDING;
                }
            }
            /* Policy: If TEMP > 48, command INLET CLOSED and HEATER OFF */
            else if (temp > 48) {
                controller->inlet_open = false;
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HEATING;
            }
        }
    } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        /* Update level freshness only */
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;

        /* Only apply control if both sensors are valid */
        if (controller->has_valid_temperature) {
            int level = input.level;
            int temp = controller->last_temperature_c;

            /* Policy: If LEVEL < 60, command INLET OPEN and HEATER OFF */
            if (level < 60) {
                controller->inlet_open = true;
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_FILLING;
            }
            /* Policy: If LEVEL > 75, command INLET CLOSED */
            else if (level > 75) {
                controller->inlet_open = false;
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HEATING;
            }
            /* Policy: If LEVEL < 55 at any time, keep HEATER OFF */
            else if (level < 55) {
                controller->inlet_open = false;
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_FILLING;
            }
            /* Policy: If 60 <= LEVEL <= 75 and TEMP < 45, command INLET CLOSED and HEATER ON */
            else if (level >= 60 && level <= 75 && temp < 45) {
                controller->inlet_open = false;
                controller->heater_on = true;
                controller->state = CONTROLLER_STATE_HEATING;
            }
            /* Policy: If 45 <= TEMP < 47, hold the previous safe heater state */
            else if (temp >= 45 && temp < 47) {
                controller->inlet_open = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            }
            /* Policy: If 47 <= TEMP <= 48 and temperature is rising, command HEATER OFF early */
            else if (temp >= 47 && temp <= 48) {
                controller->inlet_open = false;
                if (controller->previous_temperature_c > 0 && temp > controller->previous_temperature_c) {
                    controller->heater_on = false;
                    controller->state = CONTROLLER_STATE_HEATING;
                } else {
                    controller->state = CONTROLLER_STATE_HOLDING;
                }
            }
            /* Policy: If TEMP > 48, command INLET CLOSED and HEATER OFF */
            else if (temp > 48) {
                controller->inlet_open = false;
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HEATING;
            }
        }
    }

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

